export const appDBName = "nmemonica-db";
export const appDBVersion = 1;
export const IDBStores = Object.freeze({
    MEDIA: "media",
    PROGRESS: "progress",
    SETTINGS: "settings",
    WORKBOOK: "workbook"
});
export const IDBErrorCause = Object.freeze({
    NoResult: "IDBNoResults"
});
export const IDBKeys = Object.freeze({
    State: {
        EDITED: "localDataEdited"
    }
});
/**
 * indexedDB.open()
 * @param version
 */ export function openIDB() {
    let { version, logger } = arguments.length > 0 && arguments[0] !== void 0 ? arguments[0] : {};
    // const v = version!==undefined?version:appDBVersion;
    let openRequest = indexedDB.open(appDBName, version ?? appDBVersion);
    const dbUpgradeP = new Promise((resolve /*reject*/ )=>{
        openRequest.onupgradeneeded = function(event) {
            if (event.target === null) throw new Error("onupgradeneeded failed");
            // Save the IDBDatabase interface
            const db = event.target.result;
            switch(event.oldVersion){
                case 0:
                    {
                        // initial install
                        // Create an objectStore for this database
                        const mediaStore = db.createObjectStore(IDBStores.MEDIA, {
                            keyPath: "uid"
                        });
                        // Use transaction oncomplete to make sure the objectStore creation is
                        // finished before adding data into it.
                        const mediaStoreP = new Promise((mediaRes, _reject)=>{
                            mediaStore.transaction.oncomplete = function() {
                                mediaRes();
                            };
                        });
                        const stateStore = db.createObjectStore(IDBStores.PROGRESS, {
                            keyPath: "key"
                        });
                        const stateStoreP = new Promise((stateRes, _reject)=>{
                            stateStore.transaction.oncomplete = function() {
                                stateRes();
                            };
                        });
                        const settingsStore = db.createObjectStore(IDBStores.SETTINGS, {
                            keyPath: "key"
                        });
                        const settingStoreP = new Promise((settingRes, _reject)=>{
                            settingsStore.transaction.oncomplete = function() {
                                settingRes();
                            };
                        });
                        const workbookStore = db.createObjectStore(IDBStores.WORKBOOK, {
                            keyPath: "key"
                        });
                        const workbookStoreP = new Promise((workbookRes, _reject)=>{
                            workbookStore.transaction.oncomplete = function() {
                                workbookRes();
                            };
                        });
                        void Promise.all([
                            mediaStoreP,
                            stateStoreP,
                            settingStoreP,
                            workbookStoreP
                        ]).then(()=>{
                            // DONE creating db and stores
                            resolve({
                                type: "upgrade",
                                val: db
                            });
                        });
                        break;
                    }
            }
        };
    });
    const dbOpenP = new Promise((resolve, reject)=>{
        openRequest.onerror = function() {
            if (typeof logger === "function") {
                logger("IDB.open X(", 1);
            }
            reject();
        };
        openRequest.onsuccess = function(event) {
            if (event.target === null) throw new Error("openIDB failed");
            const db = event.target.result;
            db.onerror = function(event) {
                // Generic error handler for all errors targeted at this database's
                // requests!
                if (event.target && "errorCode" in event.target) {
                    const { errorCode: _errorCode } = event.target;
                    if (typeof logger === "function") {
                        logger("IDB Open X(", 1);
                    }
                }
            };
            resolve({
                type: "open",
                val: db
            });
        };
    });
    return Promise.any([
        dbUpgradeP,
        dbOpenP
    ]).then((pArr)=>{
        // if upgradeP happens wait for dbOpenP
        if (pArr.type === "upgrade") {
            return dbOpenP.then((db)=>db.val);
        }
        return pArr.val;
    });
}
/**
 * objectStore.get(key)
 */ export function getIDBItem(param, key) {
    let { db, store, logger } = param;
    const defaultStore = IDBStores.MEDIA;
    const transaction = db.transaction([
        store ?? defaultStore
    ]);
    const request = transaction.objectStore(store ?? defaultStore).get(key);
    const requestP = new Promise((resolve, reject)=>{
        request.onerror = function() {
            if (typeof logger === "function") {
                logger("IDB.get X(", 1);
            }
            reject();
        };
        request.onsuccess = function() {
            if (request.result) {
                resolve(request.result);
            } else {
                reject(new Error("No results found", {
                    cause: {
                        code: IDBErrorCause.NoResult
                    }
                }));
            }
        };
    });
    const transactionP = new Promise((resolve, reject)=>{
        transaction.oncomplete = function() {
            resolve(undefined);
        };
        transaction.onerror = function() {
            reject();
        };
    });
    return Promise.all([
        requestP,
        transactionP
    ]).then((pArr)=>pArr[0]);
}
/**
 * objectStore.add(value)
 */ export function addIDBItem(param, value) {
    let { db, store } = param;
    const defaultStore = IDBStores.MEDIA;
    let transaction = db.transaction([
        store ?? defaultStore
    ], "readwrite");
    let request = transaction.objectStore(store ?? defaultStore).add(value);
    const requestP = new Promise((resolve, reject)=>{
        request.onsuccess = function() {
            resolve(undefined);
        };
        request.onerror = function() {
            // clientLogger("IDB.add X(", DebugLevel.ERROR);
            reject();
        };
    });
    const transactionP = new Promise((resolve, reject)=>{
        transaction.oncomplete = function() {
            resolve(value);
        };
        transaction.onerror = function() {
            reject();
        };
    });
    return Promise.all([
        requestP,
        transactionP
    ]).then((arrP)=>arrP[1]);
}
