/**
 * x to 2d string[][]
 *
 * Creates a matrix of strings from xSpreadsheet data object
 * @param xObj
 */ export function xtom(xObj) {
    const matrix = Object.values(xObj.rows).reduce((yCol, row)=>{
        if (typeof row !== "number" && typeof row.cells === "object" && Object.keys(row.cells).length > 0) {
            // if cell is empty row will not contain index
            // missing indexes are normal, orderdering based on index.
            const cellIdx = Object.keys(row.cells).map((k)=>Number(k));
            const rowArr = cellIdx.reduce((xRow, x)=>{
                if (row.cells[x] !== undefined && "text" in row.cells[x]) {
                    const { text } = row.cells[x];
                    if (text !== undefined) {
                        xRow[Number(x)] = text;
                    }
                }
                return xRow;
            }, new Array(cellIdx.length));
            yCol = [
                ...yCol,
                rowArr
            ];
        }
        return yCol;
    }, []);
    return matrix;
}
/**
 * x to cell array
 *
 * Creates a cell array from xSpreadsheet data object
 * @param xObj
 * @param sheetName
 */ export function xtoc(xObj) {
    const cellArray = Object.values(xObj.rows).reduce((acc, row, xIdx)=>{
        if (typeof row !== "number" && typeof row.cells === "object") {
            const x = Object.values(row.cells).map((c, yIdx)=>[
                    xIdx,
                    yIdx,
                    c.text ?? ""
                ]);
            acc = [
                ...acc,
                ...x
            ];
        }
        return acc;
    }, []);
    return cellArray;
}
